<script setup lang="ts">
const supabase = useSupabaseClient<any>(), open = ref(false), command = ref(''), loading = ref(false), result = ref<any>(null), error = ref('')
async function run() { if (!command.value.trim()) return; loading.value = true; error.value = ''; try { const { data: { session } } = await supabase.auth.getSession(); const response: any = await $fetch('/api/constitution/action', { method:'POST', body:{ action:'command', values:{ command:command.value } }, headers:session?.access_token?{authorization:`Bearer ${session.access_token}`}:{}}); result.value=response.command } catch(e:any){error.value=e?.data?.message||e?.message||'Command could not be resolved.'} finally{loading.value=false} }
async function go(){ if(!result.value?.destination)return; open.value=false; const to=result.value.destination; result.value=null; command.value=''; await navigateTo(to) }
function keys(event:KeyboardEvent){ if((event.metaKey||event.ctrlKey)&&event.key.toLowerCase()==='k'){event.preventDefault();open.value=!open.value} if(event.key==='Escape')open.value=false }
onMounted(()=>window.addEventListener('keydown',keys)); onUnmounted(()=>window.removeEventListener('keydown',keys))
</script>
<template><button type="button" class="fixed bottom-4 right-4 z-40 rounded-full border bg-white px-3 py-2 text-[10px] text-gray-600 shadow-lg" aria-label="Open universal command" aria-haspopup="dialog" :aria-expanded="open" @click="open=true">⌘K Command</button><div v-if="open" class="fixed inset-0 z-[150] grid place-items-start bg-gray-950/40 p-4 pt-[12vh]" role="dialog" aria-modal="true" aria-label="Universal capability command" @mousedown.self="open=false"><section class="mx-auto w-full max-w-2xl rounded-2xl bg-white p-4 shadow-2xl"><div class="flex items-center justify-between"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-indigo-600">Universal capability command</div><h2 class="mt-1 text-sm font-semibold">Describe the outcome, not the page</h2></div><button type="button" aria-label="Close universal command" @click="open=false">×</button></div><form class="mt-4 flex gap-2" @submit.prevent="run"><input v-model="command" autofocus required class="min-w-0 flex-1 rounded-lg border px-3 py-2 text-sm" placeholder="Review sign-offs, connect GitHub, simulate a change…"><button :disabled="loading" class="rounded-lg bg-gray-900 px-4 text-xs text-white">{{loading?'Resolving…':'Resolve'}}</button></form><p v-if="error" class="mt-2 text-xs text-red-600">{{error}}</p><article v-if="result" class="mt-3 rounded-xl border border-indigo-200 bg-indigo-50 p-3"><div class="text-[10px] font-semibold text-indigo-700">{{result.capability}} → {{result.destination}}</div><p class="mt-1 text-xs text-gray-700">{{result.explanation.why}}</p><p class="mt-1 text-[10px] text-gray-500">Least privilege: {{result.explanation.scopes.join(', ')}} · proof {{result.proof.digest.slice(0,12)}}… · {{result.proof.status}}</p><div class="mt-3 flex justify-end gap-2"><button type="button" class="rounded-lg border bg-white px-3 py-2 text-xs" @click="result=null">Revise</button><button type="button" class="rounded-lg bg-indigo-600 px-3 py-2 text-xs text-white" @click="go">Open canonical destination</button></div></article><p class="mt-3 text-[9px] text-gray-400">Commands create a proof envelope before navigation. Canonical destinations never move.</p></section></div></template>
